local GUIHallMain = class("", IGUILayout)

function GUIHallMain:onLoad()
    self.reward = {}
    self.btnPropIllustrated = self:getChildWindow("LuckySkyHallMain-Prop-Illustrated-Button", GUIType.Button)
    self.btnPropIllustrated:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.clickUI()
        GUIIllustration:show()
    end)
    self:getChildWindow("LuckySkyHallMain-Prop-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.prop.Illustrated.button"))
    self.btnJob = self:getChildWindow("LuckySkyHallMain-Job-Button", GUIType.Button)
    self.btnJob:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.clickUI()
        GUIJobChoice:show()
    end)
    self:getChildWindow("LuckySkyHallMain-Job-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.hall.job.button"))

    self.ivUsePropBg = self:getChildWindow("LuckySkyHallMain-Use_Prop_Bg", GUIType.StaticImage)
    self.ivUsePropBg:SetVisible(false)
    self.ivUsePropIcon = self:getChildWindow("LuckySkyHallMain-Prop_Icon", GUIType.StaticImage)
    self.tvUsePropName = self:getChildWindow("LuckySkyHallMain-Prop_Name", GUIType.StaticText)
    self.tvUsePropTip = self:getChildWindow("LuckySkyHallMain-Prop_Tip", GUIType.StaticText)
    self.tvUsePropTip:SetText(Lang:getString("lucky.sky.use.prop.next.game"))
    self.tvUsePropNum = self:getChildWindow("LuckySkyHallMain-Prop_Num", GUIType.StaticText)
    self.tvUsePropNum:SetVisible(false)
    self:registerDataCallBack("sendUsePropData", function(data)
        self:onUsePropData(data)
    end, DataBuilderProcessor)

end

function GUIHallMain:isNeedLoad()
    return not Game:isEnableIndie()
end

function GUIHallMain:onUsePropData(data)
    HostApi.log("!!!GUIHallMain. onUsePropData")
    self.ivUsePropBg:SetVisible(true)
    local itemId = data:getNumberParam("propId")
    local number = data:getNumberParam("num")
    local name = ItemConfig:getItemNameById(itemId)
    if itemId == nil then
        HostApi.log("???GUIHallMain.reward is nil")
        self.ivUsePropBg:SetVisible(false)
        return
    end
    GuiItemStack.showItemIcon(self.ivUsePropIcon, tonumber(itemId), 0, "")
    self.tvUsePropName:SetText(string.format(Lang:getString(name) .. "  x%s", tostring(number)))
end

return GUIHallMain